from collections import defaultdict

class PinyinCounter:
    """Counts occurrences of pinyin pronunciations for Chinese characters."""

    def __init__(self):
        self.counts = defaultdict(int)

    def add(self, pinyin):
        """Increment count for a pinyin pronunciation."""
        self.counts[pinyin] += 1

    def most_common(self, n=None):
        """Return most common pinyin(s) sorted by frequency.

        Args:
            n: Number of top results to return (None for all)
        Returns:
            List of (pinyin, count) tuples sorted by count descending
        """
        sorted_items = sorted(self.counts.items(), key=lambda x: x[1], reverse=True)
        return sorted_items[:n] if n else sorted_items

def han_to_code(han_char):
    """Convert a Chinese character to its Unicode code point.

    Args:
        han_char: Single Chinese character string
    Returns:
        String in format 'U+XXXX' representing Unicode code point
    """
    return f"U+{ord(han_char):04X}"

def process_characters(character_data):
    """Process Chinese characters and their pinyin pronunciations.

    Args:
        character_data: Dictionary of {character: [pinyin_list]}
    Returns:
        Dictionary of {character: PinyinCounter} with pronunciation counts
    """
    han_counter = {}

    for character, pinyin_list in character_data.items():
        if len(character) != len(pinyin_list):
            continue

        for han_char, pinyins in zip(character, pinyin_list):
            if han_char not in han_counter:
                han_counter[han_char] = PinyinCounter()

            for pinyin in pinyins:
                han_counter[han_char].add(pinyin)

    return han_counter

import os
import pathlib

def get_sequence(sequence=None, filepath=None):
    """
    Retrieve a sequence either from a direct string input or from a file.

    Args:
        sequence (str, optional): Direct sequence string input. Defaults to None.
        filepath (str, optional): Path to file containing sequence. Defaults to None.

    Returns:
        str: The retrieved sequence, or None if neither input is valid or file not found.
    """
    if sequence is not None:
        return sequence

    if filepath is not None:
        try:
            with open(filepath, 'r') as f:
                return f.read().strip()
        except (FileNotFoundError, IOError):
            return None

    return None

import math
from math import log

def calculate_correlation(pre_freq, suf_freq, combination_freq):
    """
    Calculate the correlation between two items based on their frequencies.
    Args:
        pre_freq: Frequency of the first item
        suf_freq: Frequency of the second item
        combination_freq: Frequency of the items appearing together
    Returns:
        Correlation value between the two items
    """
    if pre_freq == suf_freq or combination_freq == 0:
        return 0.0

    # Calculate individual entropies
    def entropy(p):
        if p == 0 or p == 1:
            return 0.0
        return -p * log(p) - (1 - p) * log(1 - p)

    H_pre = entropy(pre_freq)
    H_suf = entropy(suf_freq)

    # Calculate joint entropy
    param_1 = pre_freq - combination_freq
    param_2 = suf_freq - combination_freq
    param_3 = 1 + combination_freq - pre_freq - suf_freq

    H_pre_suf = 0.0
    if combination_freq > 0:
        H_pre_suf -= combination_freq * log(combination_freq)
    if param_1 > 0:
        H_pre_suf -= param_1 * log(param_1)
    if param_2 > 0:
        H_pre_suf -= param_2 * log(param_2)
    if param_3 > 0:
        H_pre_suf -= param_3 * log(param_3)

    # Calculate correlation coefficient
    if H_pre == 0 or H_suf == 0:
        return 0.0
    return (H_pre + H_suf - H_pre_suf) / ((H_pre * H_suf) ** 0.5)

def AGNES_clustering(item_frequencies, combination_frequencies, k=3, linkage='average'):
    """
    Perform AGNES clustering on items based on their correlation.
    Args:
        item_frequencies: List of frequencies for each item
        combination_frequencies: Matrix of frequencies for item pairs
        k: Number of clusters to form
        linkage: Type of linkage ('average', 'min', or 'max')
    Returns:
        List of clusters (each cluster is a list of item indices)
    """
    n_items = len(item_frequencies)
    clusters = [[i] for i in range(n_items)]

    # Distance function selector
    def distance(Ci, Cj):
        if linkage == 'min':
            return min(calculate_correlation(item_frequencies[i], item_frequencies[j], 
                                           combination_frequencies[i][j]) 
                      for i in Ci for j in Cj)
        elif linkage == 'max':
            return max(calculate_correlation(item_frequencies[i], item_frequencies[j], 
                                           combination_frequencies[i][j]) 
                      for i in Ci for j in Cj)
        else:  # average
            total = sum(calculate_correlation(item_frequencies[i], item_frequencies[j], 
                                            combination_frequencies[i][j]) 
                       for i in Ci for j in Cj)
            return total / (len(Ci) * len(Cj))

    # Initialize distance matrix
    distance_matrix = []
    for i in range(n_items):
        row = []
        for j in range(n_items):
            if i == j:
                row.append(0.0)
            else:
                row.append(calculate_correlation(item_frequencies[i], item_frequencies[j],
                                               combination_frequencies[i][j]))
        distance_matrix.append(row)

    while len(clusters) > k:
        # Find closest clusters
        max_dist = -1
        x, y = 0, 0
        for i in range(len(clusters)):
            for j in range(i+1, len(clusters)):
                dist = distance(clusters[i], clusters[j])
                if dist > max_dist:
                    max_dist = dist
                    x, y = i, j

        # Merge clusters
        clusters[x].extend(clusters[y])
        del clusters[y]

    return clusters

