from collections import defaultdict

class DFA:
    """Simplified DFA representation for demonstration purposes."""
    def __init__(self, states, inputs, outputs, start, transitions):
        self.states = states
        self.inputs = inputs
        self.outputs = outputs
        self.start = start
        self.transitions = transitions  # dict: (state, input) -> (next_state, output)

def dfa_to_aig_simple(dfa):
    """
    Simplified version of converting a DFA to an AIG-like representation.
    Returns a tuple containing:
    1. A transition table (dictionary mapping (current_state, input) to next_state)
    2. An output table (dictionary mapping state to output)
    3. A validity checker (boolean indicating if input is valid)
    """
    # Create transition table
    transition_table = {}
    for (state, input_symbol), (next_state, _) in dfa.transitions.items():
        transition_table[(state, input_symbol)] = next_state

    # Create output table
    output_table = {}
    for state in dfa.states:
        # Find any transition from this state to get its output
        for (s, _), (_, output) in dfa.transitions.items():
            if s == state:
                output_table[state] = output
                break

    # Create input validity checker
    def is_valid_input(input_symbol):
        return input_symbol in dfa.inputs

    return transition_table, output_table, is_valid_input

import numpy as np

def product_matern_covariance(x0, x1=None, lengthscales=1.0, nus=1.5):
    """
    Compute the tensor product of 1D Matérn covariance functions.

    Parameters:
    x0 (np.ndarray): First input array of shape (n_samples, n_features) or (n_features,)
    x1 (np.ndarray, optional): Second input array of same shape as x0. If None, computes auto-covariance.
    lengthscales (float or np.ndarray): Lengthscale parameters for each dimension.
    nus (float or np.ndarray): Smoothness parameters for each dimension.

    Returns:
    float or np.ndarray: The computed covariance value(s)
    """
    # Convert inputs to proper numpy arrays
    x0 = np.asarray(x0)
    if x1 is not None:
        x1 = np.asarray(x1)

    # Handle scalar inputs
    if x0.ndim == 0:
        x0 = np.array([x0])
    if x1 is not None and x1.ndim == 0:
        x1 = np.array([x1])

    # Ensure lengthscales and nus are arrays
    lengthscales = np.atleast_1d(lengthscales)
    nus = np.atleast_1d(nus)

    # Broadcast scalars to all dimensions
    if len(lengthscales) == 1 and x0.size > 1:
        lengthscales = np.full(x0.size, lengthscales[0])
    if len(nus) == 1 and x0.size > 1:
        nus = np.full(x0.size, nus[0])

    # Compute 1D Matern covariances for each dimension
    def _matern_1d(r, lengthscale, nu):
        r_scaled = np.abs(r) / lengthscale
        if r_scaled == 0:
            return 1.0
        if nu == 0.5:
            return np.exp(-r_scaled)
        if nu == 1.5:
            return (1 + np.sqrt(3) * r_scaled) * np.exp(-np.sqrt(3) * r_scaled)
        if nu == 2.5:
            return (1 + np.sqrt(5) * r_scaled + (5/3) * r_scaled**2) * np.exp(-np.sqrt(5) * r_scaled)
        return 1.0  # Default case

    # Compute product of 1D covariances
    result = 1.0
    for dim in range(x0.size):
        if x1 is None:
            r = 0.0  # Auto-covariance
        else:
            r = x0[dim] - x1[dim]
        result *= _matern_1d(r, lengthscales[dim], nus[dim])

    return result

class Library:
    def __init__(self):
        self.books = []
        self.load_books()

    def load_books(self):
        """Initialize with some default books for testing"""
        self.books = [
            {"title": "Python Basics", "author": "John Doe", "quantity": 5, "price": 29.99},
            {"title": "Advanced Python", "author": "Jane Smith", "quantity": 3, "price": 39.99},
            {"title": "Data Science", "author": "Alice Johnson", "quantity": 2, "price": 49.99}
        ]

    def add_book(self, title, author, quantity, price):
        """Add a new book to the library"""
        self.books.append({
            "title": title,
            "author": author,
            "quantity": quantity,
            "price": price
        })
        return True

    def borrow_book(self, title):
        """Borrow a book from the library"""
        for book in self.books:
            if book["title"].lower() == title.lower():
                if book["quantity"] > 0:
                    book["quantity"] -= 1
                    return True, book
                else:
                    return False, "Book out of stock"
        return False, "Book not found"

    def return_book(self, title):
        """Return a book to the library"""
        for book in self.books:
            if book["title"].lower() == title.lower():
                book["quantity"] += 1
                return True, book
        return False, "Book not found in our records"

    def search_book(self, query):
        """Search for books by title or author"""
        results = []
        for book in self.books:
            if query.lower() in book["title"].lower() or query.lower() in book["author"].lower():
                results.append(book)
        return results

