def count_triangles(adjacency_matrix):
    """
    Counts the number of triangles in an undirected graph represented by an adjacency matrix.

    Args:
        adjacency_matrix: A square matrix (list of lists) where 1 represents an edge and 0 represents no edge.

    Returns:
        The number of triangles found in the graph.
    """
    n = len(adjacency_matrix)
    total_count = 0

    # Check all possible triplets of vertices (a, b, c)
    for a in range(n):
        for b in range(a + 1, n):
            if not adjacency_matrix[a][b]:
                continue  # Skip if no edge between a and b
            for c in range(b + 1, n):
                if adjacency_matrix[b][c] and adjacency_matrix[a][c]:
                    total_count += 1
    return total_count

def analyze_last_digit(number):
    """
    Analyzes the last digit of a given integer and returns a descriptive string.

    Args:
        number (int): The integer to analyze

    Returns:
        str: A message describing the properties of the last digit
    """
    # Calculate last digit, handling negative numbers correctly
    if number < 0:
        last_digit = -((-1 * number) % 10)
    else:
        last_digit = number % 10

    # Determine the properties of the last digit
    if last_digit == 0:
        return f"Last digit of {number} is {last_digit} and is 0"
    elif last_digit > 5:
        return f"Last digit of {number} is {last_digit} and is greater than 5"
    else:
        return f"Last digit of {number} is {last_digit} and is less than 6 and not 0"

