def validate_variable_name(name):
    """
    Validates if a given string is a valid Python variable name according to PEP 8 conventions.
    Returns a tuple of (is_valid, message) where:
    - is_valid: bool indicating if the name is valid
    - message: str with explanation if invalid
    """
    import keyword

    # Check if empty
    if not name:
        return (False, "Variable name cannot be empty")

    # Check if it's a Python keyword
    if keyword.iskeyword(name):
        return (False, f"'{name}' is a Python keyword and cannot be used as a variable name")

    # Check first character
    if not (name[0].isalpha() or name[0] == '_'):
        return (False, "Variable name must start with a letter or underscore")

    # Check remaining characters
    for char in name[1:]:
        if not (char.isalnum() or char == '_'):
            return (False, f"Variable name contains invalid character '{char}'")

    # Check PEP 8 style recommendations
    if '__' in name and not (name.startswith('__') and name.endswith('__')):
        return (True, "Valid but discouraged: name contains double underscores (reserved for magic methods)")

    if name[0] == '_' and not (name.startswith('__') and name.endswith('__')):
        return (True, "Valid but note: single leading underscore indicates 'internal use' convention")

    if any(c.isupper() for c in name) and '_' not in name:
        return (True, "Valid but note: PascalCase is typically used for class names, not variables")

    return (True, "Valid variable name following PEP 8 conventions")

def demonstrate_dict_methods(input_dict, method_name, *args):
    """
    Demonstrates various dictionary methods based on the method_name provided.
    Handles different dictionary operations safely with proper error checking.

    Args:
        input_dict: The dictionary to operate on
        method_name: String name of the method to demonstrate
        *args: Additional arguments required by some methods (e.g., key for get())

    Returns:
        Result of the dictionary operation or error message if invalid
    """
    if not isinstance(input_dict, dict):
        return "Error: First argument must be a dictionary"

    method_name = method_name.lower()

    try:
        if method_name == 'clear':
            input_dict.clear()
            return "Dictionary cleared"

        elif method_name == 'copy':
            return input_dict.copy()

        elif method_name == 'fromkeys':
            if len(args) < 1:
                return "Error: fromkeys requires at least a sequence of keys"
            value = args[1] if len(args) > 1 else None
            return dict.fromkeys(args[0], value)

        elif method_name == 'get':
            if len(args) < 1:
                return "Error: get requires a key argument"
            default = args[1] if len(args) > 1 else None
            return input_dict.get(args[0], default)

        elif method_name == 'items':
            return list(input_dict.items())

        elif method_name == 'keys':
            return list(input_dict.keys())

        elif method_name == 'pop':
            if len(args) < 1:
                return "Error: pop requires a key argument"
            default = args[1] if len(args) > 1 else None
            return input_dict.pop(args[0], default)

        elif method_name == 'popitem':
            if not input_dict:
                return "Error: dictionary is empty"
            return input_dict.popitem()

        elif method_name == 'setdefault':
            if len(args) < 1:
                return "Error: setdefault requires a key argument"
            default = args[1] if len(args) > 1 else None
            return input_dict.setdefault(args[0], default)

        elif method_name == 'update':
            if len(args) < 1:
                return "Error: update requires a dictionary or iterable"
            input_dict.update(args[0])
            return "Dictionary updated"

        elif method_name == 'values':
            return list(input_dict.values())

        else:
            return f"Error: Unknown method '{method_name}'"

    except Exception as e:
        return f"Error: {str(e)}"

class LecturerManager:
    """A class to manage lecturer records in memory without file I/O"""

    def __init__(self):
        self.lecturer_fields = ['ID', 'First Name', 'Last Name', 'Email', 'Phone', 'Course']
        self.lecturers = []

    def add_lecturer(self, lecturer_data):
        """Add a new lecturer record"""
        if len(lecturer_data) != len(self.lecturer_fields):
            return False, "Invalid data length"

        # Check for duplicate ID
        for lecturer in self.lecturers:
            if lecturer[0] == lecturer_data[0]:
                return False, "Duplicate ID"

        self.lecturers.append(lecturer_data)
        return True, "Lecturer added successfully"

    def view_lecturers(self):
        """Return all lecturer records"""
        return self.lecturers

    def search_lecturer(self, lecturer_id):
        """Search for a lecturer by ID"""
        for lecturer in self.lecturers:
            if lecturer[0] == lecturer_id:
                return True, lecturer
        return False, "Lecturer not found"

    def update_lecturer(self, lecturer_id, new_data):
        """Update a lecturer record"""
        if len(new_data) != len(self.lecturer_fields):
            return False, "Invalid data length"

        for i, lecturer in enumerate(self.lecturers):
            if lecturer[0] == lecturer_id:
                # Don't allow ID change
                if new_data[0] != lecturer_id:
                    return False, "Cannot change lecturer ID"
                self.lecturers[i] = new_data
                return True, "Lecturer updated successfully"
        return False, "Lecturer not found"

    def delete_lecturer(self, lecturer_id):
        """Delete a lecturer record"""
        for i, lecturer in enumerate(self.lecturers):
            if lecturer[0] == lecturer_id:
                del self.lecturers[i]
                return True, "Lecturer deleted successfully"
        return False, "Lecturer not found"

import math

class Point:
    """Represents a point in 2D space with x and y coordinates."""

    def __init__(self, x, y):
        self.x = x
        self.y = y

    def move_by(self, dx, dy):
        """Move the point by given offsets in x and y directions."""
        self.x += dx
        self.y += dy

    def distance_to(self, other_point):
        """Calculate Euclidean distance to another point."""
        return math.sqrt((self.x - other_point.x) ** 2 + (self.y - other_point.y) ** 2)

    def __str__(self):
        """String representation of the point."""
        return f'({self.x},{self.y})'


class LineSegment:
    """Represents a line segment between two points in 2D space."""

    def __init__(self, start, end):
        self.start = start
        self.end = end

    @classmethod
    def from_coordinates(cls, x1, y1, x2, y2):
        """Alternative constructor using direct coordinates."""
        start = Point(x1, y1)
        end = Point(x2, y2)
        return cls(start, end)

    @property
    def length(self):
        """Calculate the length of the line segment."""
        return self.start.distance_to(self.end)

    def __str__(self):
        """String representation of the line segment."""
        return (f'\nStart point: {self.start}'
                f'\nEnd point: {self.end}'
                f'\nLength: {self.length}')

