def compute_attribute_closure(attributes, functional_deps):
    """
    Compute the closure of a set of attributes given functional dependencies.

    Args:
        attributes (str): The set of attributes to compute closure for (e.g., 'A', 'CD')
        functional_deps (dict): Functional dependencies in format {'AB': ['C'], 'C': ['AD']}

    Returns:
        str: The closure of the input attributes (e.g., 'ABCD')
    """
    closure = set(attributes)
    changed = True

    while changed:
        changed = False
        # Check each functional dependency
        for lhs, rhs_list in functional_deps.items():
            for rhs in rhs_list:
                # If all attributes in LHS are in our current closure
                if all(attr in closure for attr in lhs):
                    # Add RHS attributes to closure if not already present
                    for attr in rhs:
                        if attr not in closure:
                            closure.add(attr)
                            changed = True
    return ''.join(sorted(closure))

