from math import log

class NaiveBayesClassifier:
    """
    A simplified Naive Bayes classifier for sentiment analysis.
    Processes text data and classifies it as 'pos' (positive) or 'neg' (negative).
    Uses Laplace smoothing to handle unseen words.
    """

    def __init__(self):
        self.word_counts = {'pos': defaultdict(int), 'neg': defaultdict(int)}
        self.class_counts = {'pos': 0, 'neg': 0}
        self.total_words = {'pos': 0, 'neg': 0}

    def train(self, labeled_data):
        """
        Train the classifier with labeled data.
        labeled_data: List of tuples in format (text, label) where label is 'pos' or 'neg'
        """
        for text, label in labeled_data:
            self.class_counts[label] += 1
            tokens = self._tokenize(text)
            for token in tokens:
                self.word_counts[label][token] += 1
                self.total_words[label] += 1

    def predict(self, text):
        """
        Predict the sentiment of a given text.
        Returns a tuple of (predicted_label, confidence_score)
        """
        tokens = self._tokenize(text)

        # Calculate log probabilities to avoid underflow
        log_prob_pos = log(self.class_counts['pos'] / sum(self.class_counts.values()))
        log_prob_neg = log(self.class_counts['neg'] / sum(self.class_counts.values()))

        vocab_size = len(set(self.word_counts['pos'].keys()) | set(self.word_counts['neg'].keys()))

        for token in tokens:
            # Laplace smoothing
            count_pos = self.word_counts['pos'].get(token, 0) + 1
            count_neg = self.word_counts['neg'].get(token, 0) + 1

            log_prob_pos += log(count_pos / (self.total_words['pos'] + vocab_size))
            log_prob_neg += log(count_neg / (self.total_words['neg'] + vocab_size))

        if log_prob_pos > log_prob_neg:
            confidence = 1 / (1 + (log_prob_neg - log_prob_pos))
            return ('pos', confidence)
        else:
            confidence = 1 / (1 + (log_prob_pos - log_prob_neg))
            return ('neg', confidence)

    def _tokenize(self, text):
        """Simple tokenizer that splits on whitespace and lowercases"""
        return text.lower().split()

