from datetime import datetime, timedelta

class DateTimeOperations:
    """Core datetime operations extracted from the original test cases"""

    def __init__(self, base_time=None):
        """Initialize with a base time (defaults to current time if None)"""
        self.base_time = base_time or datetime.utcnow()

    def add_interval(self, interval_str):
        """
        Add a time interval to the base time.
        Interval string format: '1 day', '2 hours', '30 minutes', etc.
        Returns the new datetime.
        """
        try:
            value, unit = interval_str.split()
            value = int(value)

            if unit in ('day', 'days'):
                delta = timedelta(days=value)
            elif unit in ('hour', 'hours'):
                delta = timedelta(hours=value)
            elif unit in ('minute', 'minutes'):
                delta = timedelta(minutes=value)
            elif unit in ('second', 'seconds'):
                delta = timedelta(seconds=value)
            else:
                raise ValueError(f"Unknown time unit: {unit}")

            return self.base_time + delta
        except Exception as e:
            raise ValueError(f"Invalid interval format: {interval_str}. Expected format: '1 day'") from e

    def get_time_part(self, part):
        """
        Get a specific part of the datetime (hour, minute, second).
        Returns the requested part as an integer.
        """
        part = part.lower()
        if part == 'hour':
            return self.base_time.hour
        elif part == 'minute':
            return self.base_time.minute
        elif part == 'second':
            return self.base_time.second
        else:
            raise ValueError(f"Unknown time part: {part}. Must be 'hour', 'minute', or 'second'")

    def truncate_time(self, precision):
        """
        Truncate the datetime to the specified precision.
        Returns a new datetime truncated to the given precision.
        """
        precision = precision.lower()
        if precision == 'hour':
            return self.base_time.replace(minute=0, second=0, microsecond=0)
        elif precision == 'minute':
            return self.base_time.replace(second=0, microsecond=0)
        elif precision == 'second':
            return self.base_time.replace(microsecond=0)
        else:
            raise ValueError(f"Unknown precision: {precision}. Must be 'hour', 'minute', or 'second'")

    def is_finite(self):
        """Check if the datetime is finite (always True for regular datetimes)"""
        return True

