class TreeNode:
    """A simplified tree node class to replace TreeItem from the original code"""
    def __init__(self, data, parent=None):
        self._data = data
        self._parent = parent
        self._children = []

    def data(self, column):
        """Return data for the given column"""
        if column < len(self._data):
            return self._data[column]
        return None

    def setData(self, column, value):
        """Set data for the given column"""
        if column < len(self._data):
            self._data[column] = value
            return True
        return False

    def child(self, row):
        """Get child at specified row"""
        if 0 <= row < len(self._children):
            return self._children[row]
        return None

    def childCount(self):
        """Return number of children"""
        return len(self._children)

    def childNumber(self):
        """Return this node's position in its parent's children list"""
        if self._parent:
            return self._parent._children.index(self)
        return 0

    def columnCount(self):
        """Return number of data columns"""
        return len(self._data)

    def parent(self):
        """Return parent node"""
        return self._parent

    def insertChildren(self, position, count, columns):
        """Insert child nodes"""
        if position < 0 or position > len(self._children):
            return False

        for row in range(count):
            data = [None] * columns
            node = TreeNode(data, self)
            self._children.insert(position + row, node)

        return True

    def removeChildren(self, position, count):
        """Remove child nodes"""
        if position < 0 or position + count > len(self._children):
            return False

        del self._children[position:position+count]
        return True

    def insertColumns(self, position, columns):
        """Insert columns into node and all children"""
        if position < 0 or position > len(self._data):
            return False

        for column in range(columns):
            self._data.insert(position, None)

        for child in self._children:
            child.insertColumns(position, columns)

        return True

    def removeColumns(self, position, columns):
        """Remove columns from node and all children"""
        if position < 0 or position + columns > len(self._data):
            return False

        del self._data[position:position+columns]

        for child in self._children:
            child.removeColumns(position, columns)

        return True


class TreeModel:
    """A simplified tree model without Qt dependencies"""
    def __init__(self, headers):
        root_data = headers.copy()
        self._root_item = TreeNode(root_data)

    def root_item(self):
        """Return the root item"""
        return self._root_item

    def get_item(self, row_path):
        """
        Get item by path (list of row indices from root)
        Returns None if path is invalid
        """
        item = self._root_item
        for row in row_path:
            if row < 0 or row >= item.childCount():
                return None
            item = item.child(row)
        return item

    def row_count(self, row_path):
        """Get number of children for item at given path"""
        item = self.get_item(row_path)
        return item.childCount() if item else 0

    def column_count(self):
        """Get number of columns"""
        return self._root_item.columnCount()

    def data(self, row_path, column):
        """Get data at given path and column"""
        item = self.get_item(row_path)
        return item.data(column) if item else None

    def set_data(self, row_path, column, value):
        """Set data at given path and column"""
        item = self.get_item(row_path)
        return item.setData(column, value) if item else False

    def insert_rows(self, row_path, position, count):
        """Insert rows at given path"""
        parent = self.get_item(row_path)
        if not parent:
            return False
        return parent.insertChildren(position, count, self.column_count())

    def remove_rows(self, row_path, position, count):
        """Remove rows at given path"""
        parent = self.get_item(row_path)
        if not parent:
            return False
        return parent.removeChildren(position, count)

    def insert_columns(self, position, columns):
        """Insert columns at given position"""
        return self._root_item.insertColumns(position, columns)

    def remove_columns(self, position, columns):
        """Remove columns at given position"""
        return self._root_item.removeColumns(position, columns)

def count_triangles(adjacency_matrix):
    """
    Counts the number of triangles in an undirected graph represented by an adjacency matrix.

    Args:
        adjacency_matrix: A square matrix (list of lists) where 1 represents an edge and 0 represents no edge.

    Returns:
        The number of triangles found in the graph.
    """
    n = len(adjacency_matrix)
    total_count = 0

    # Check all possible triplets of vertices (a, b, c)
    for a in range(n):
        for b in range(a + 1, n):
            if not adjacency_matrix[a][b]:
                continue  # Skip if no edge between a and b
            for c in range(b + 1, n):
                if adjacency_matrix[b][c] and adjacency_matrix[a][c]:
                    total_count += 1
    return total_count

