        Args:
            entity_type: The type of entity (top-level category)
            name: The name of the specific entity
            attribute: The attribute name to set
            value: The value to store
            unit: The unit of measurement
        """
        if entity_type not in self.entity_map:
            self.entity_map[entity_type] = {}
        if name not in self.entity_map[entity_type]:
            self.entity_map[entity_type][name] = {}
        self.entity_map[entity_type][name][attribute] = Value(value, unit)

    def get_attribute(self, entity_type, name, attribute):
        """
        Retrieves an attribute value with its unit.

        Returns:
            Value object or None if not found
        """
        try:
            return self.entity_map[entity_type][name][attribute]
        except KeyError:
            return None

class UserManager:
    """Manages user registration and authentication without Flask dependencies."""

    def __init__(self):
        self.users = {}  # username: {'email': str, 'password': str}
        self.sessions = set()  # active usernames

    def register_user(self, username, email, password):
        """
        Register a new user if username and email are unique.
        Returns True if registration was successful, False otherwise.
        """
        if username in self.users:
            return False, "Username already exists"
        if any(user['email'] == email for user in self.users.values()):
            return False, "Email already registered"

        self.users[username] = {
            'email': email,
            'password': password
        }
        return True, "Registration successful"

    def login_user(self, username, password):
        """
        Authenticate a user with given credentials.
        Returns True if login was successful, False otherwise.
        """
        if username not in self.users:
            return False, "Username not found"
        if self.users[username]['password'] != password:
            return False, "Incorrect password"

        self.sessions.add(username)
        return True, "Login successful"

    def logout_user(self, username):
        """
        Log out a user by removing them from active sessions.
        """
        if username in self.sessions:
            self.sessions.remove(username)
        return True, "Logout successful"

    def is_logged_in(self, username):
        """Check if a user is currently logged in."""
        return username in self.sessions

