def find_numbers_with_remainders(val1, val2):
    """
    Find all numbers between two given values (exclusive) that have a remainder 
    of 2 or 3 when divided by 5.

    Args:
        val1 (int): First boundary value
        val2 (int): Second boundary value

    Returns:
        list: A sorted list of numbers meeting the criteria
    """
    result = []

    if val1 < val2:
        val1 += 1
        while val1 < val2:
            if val1 % 5 == 2 or val1 % 5 == 3:
                result.append(val1)
            val1 += 1
    elif val2 < val1:
        val2 += 1
        while val2 < val1:
            if val2 % 5 == 2 or val2 % 5 == 3:
                result.append(val2)
            val2 += 1

    return sorted(result)

