from PIL import Image
import numpy as np

def rescale_image(image, output_size):
    """
    Rescales an image to a given size while optionally maintaining aspect ratio.

    Args:
        image: Input image as either a PIL Image or numpy array
        output_size: Desired output size. If tuple, exact resize. If int, maintains aspect ratio.

    Returns:
        Resized PIL Image
    """
    # Convert numpy array to PIL Image if needed
    if isinstance(image, np.ndarray):
        pil_image = Image.fromarray(image)
    else:
        pil_image = image.copy()

    # Handle different output_size types
    if isinstance(output_size, tuple):
        # Exact resize to specified dimensions
        return pil_image.resize((int(output_size[0]), int(output_size[1])))
    else:
        # Maintain aspect ratio
        width, height = pil_image.size
        if width < height:
            new_size = (int(output_size), int(height * output_size / width))
        else:
            new_size = (int(width * output_size / height), int(output_size))
        return pil_image.resize(new_size)

