import numpy as np
from typing import List, Dict, Union, Tuple

def create_legend_config(legend_type: str = 'simple', 
                        labels: Union[List[str], Tuple[str, str]] = None,
                        **kwargs) -> Dict:
    """
    Create configuration data for different types of matplotlib legends.

    Args:
        legend_type: Type of legend to create ('simple', 'complex', 'multi_key', 'custom')
        labels: Labels for the legend items
        **kwargs: Additional customization parameters

    Returns:
        Dictionary containing legend configuration data
    """
    config = {
        'type': legend_type,
        'labels': labels or [],
        'properties': {}
    }

    if legend_type == 'simple':
        config['properties'].update({
            'loc': kwargs.get('loc', 'upper right'),
            'shadow': kwargs.get('shadow', False),
            'title': kwargs.get('title', None),
            'title_color': kwargs.get('title_color', 'black')
        })

    elif legend_type == 'complex':
        config['properties'].update({
            'bbox_to_anchor': kwargs.get('bbox_to_anchor', [0, 1]),
            'ncol': kwargs.get('ncol', 1),
            'fancybox': kwargs.get('fancybox', False),
            'shadow': kwargs.get('shadow', False)
        })

    elif legend_type == 'multi_key':
        config['properties'].update({
            'scatterpoints': kwargs.get('scatterpoints', 1),
            'numpoints': kwargs.get('numpoints', 1),
            'handler_map': kwargs.get('handler_map', {}),
            'ndivide': kwargs.get('ndivide', None),
            'pad': kwargs.get('pad', None)
        })

    elif legend_type == 'custom':
        config['properties'].update({
            'handlelength': kwargs.get('handlelength', 2.5),
            'handleheight': kwargs.get('handleheight', 3),
            'handler_map': kwargs.get('handler_map', {})
        })

    return config

def generate_legend_data(legend_type: str) -> Dict:
    """
    Generate sample data for different types of legends.
    Used for testing and demonstration purposes.
    """
    if legend_type == 'simple':
        return create_legend_config(
            legend_type='simple',
            labels=['oscillatory', 'damped'],
            loc='upper right',
