import json

class MockZulipClient:
    """Mock client to simulate Zulip API interactions for testing"""
    def __init__(self):
        self.sent_messages = []

    def send_message(self, message):
        """Store sent messages for verification"""
        self.sent_messages.append(message)
        return {"result": "success", "msg": ""}

def get_recipients(msg):
    """Extract recipient emails from a message"""
    if isinstance(msg['display_recipient'], list):
        return [recipient['email'] for recipient in msg['display_recipient']]
    return []

def send_message(client, msg, content):
    """
    Send a message based on its type (stream or private)
    Args:
        client: Zulip client instance
        msg: Dictionary containing message details
        content: Message content to send
    """
    if msg['type'] == 'stream':
        client.send_message({
            "type": "stream",
            "subject": msg["subject"],
            "to": msg['display_recipient'],
            "content": content
        })
    else:
        recipients = get_recipients(msg)
        recipients.append(msg['sender_email'])
        client.send_message({
            "type": 'private',
            "subject": msg['subject'],
            "to": json.dumps(recipients),
            "content": content
        })

class PageView:
    """
    A class that provides different functionality based on user role.
    Uses dynamic method generation through __getattr__ to provide role-specific methods.
    """
    def __init__(self, role="user"):
        """
        Initialize the PageView with a specific role.
        Valid roles are 'admin' and 'user' (default).
        """
        if role not in ('admin', 'user'):
            raise ValueError("Invalid role. Must be 'admin' or 'user'")
        self.role = role

    def __getattr__(self, attr):
        """
        Dynamically generates methods based on the user's role.
        Returns appropriate functions for valid method names,
        raises AttributeError for invalid method names.
        """
        if self.role == 'admin':
            def getstats():
                return "Admin statistics: system metrics, user activity, etc."

            def adduser():
                return "Admin function: adding new user to system."

            if attr == 'getstats':
                return getstats
            elif attr == 'adduser':
                return adduser

        elif self.role == 'user':
            def getstats():
                return "User statistics: personal activity, usage metrics."

            def show_home():
                return "Displaying user home page with personalized content."

            if attr == 'getstats':
                return getstats
            elif attr == 'show_home':
                return show_home

        raise AttributeError(f"'{self.role}' role has no method '{attr}'")

