import uuid
from datetime import datetime

class TimerService:
    def __init__(self):
        self.timers = {}
        self.stash = {}

    def start_timer(self, name=None):
        """Start a timer with optional name, returns timer ID"""
        timer_id = str(uuid.uuid1()) if name is None else name
        self.timers[timer_id] = datetime.now()
        return timer_id

    def end_timer(self, timer_id):
        """End a timer and return duration in seconds"""
        if timer_id not in self.timers:
            raise ValueError("Timer ID not found")

        start_time = self.timers[timer_id]
        duration = datetime.now() - start_time
        return duration.total_seconds()

    def get_all_timers(self):
        """Return all active timers"""
        return {k: v.isoformat() for k, v in self.timers.items()}

    def stash_item(self, item):
        """Store an item in stash and return its ID"""
        item_id = str(uuid.uuid1())
        self.stash[item_id] = item
        return item_id

    def unstash_item(self, item_id):
        """Retrieve an item from stash by ID"""
        if item_id not in self.stash:
            raise ValueError("Item ID not found")
        return self.stash[item_id]

    @staticmethod
    def split_string(splitter, item):
        """Split a string by the given splitter"""
        return item.split(splitter)

def check_number_sign(number_str):
    """
    Determines if a given string represents a positive, negative, or zero number.

    Args:
        number_str (str): String input to be checked

    Returns:
        str: "Positive" if number > 0, "Negative" if number < 0, 
             "Zero" if number == 0, or "Invalid" if not a valid number
    """
    try:
        num = float(number_str)
        if num > 0:
            return "Positive"
        elif num < 0:
            return "Negative"
        else:
            return "Zero"
    except ValueError:
        return "Invalid"

import numpy as np
from typing import List, Dict, Optional, Union

def calculate_clustering_metrics(
    labels: List[int],
    data: Optional[np.ndarray] = None,
    gold_standard: Optional[List[int]] = None,
    methods: List[str] = ['silhouette', 'calinski_harabasz', 'davies_bouldin']
) -> Dict[str, float]:
    """
    Calculate clustering evaluation metrics for given labels.

    Args:
        labels: Cluster labels for each data point.
        data: Input data matrix (n_samples, n_features). Required for some metrics.
        gold_standard: Ground truth labels (if available). Required for supervised metrics.
        methods: List of metrics to calculate. Supported: 'silhouette', 'calinski_harabasz', 
                'davies_bouldin', 'adjusted_rand', 'adjusted_mutual_info'.

    Returns:
        Dictionary with metric names as keys and their scores as values.
    """
    from sklearn import metrics

    results = {}

    for method in methods:
        try:
            if method == 'silhouette':
                if data is None:
                    raise ValueError("Data required for silhouette score")
                results[method] = metrics.silhouette_score(data, labels)
            elif method == 'calinski_harabasz':
                if data is None:
                    raise ValueError("Data required for Calinski-Harabasz score")
                results[method] = metrics.calinski_harabasz_score(data, labels)
            elif method == 'davies_bouldin':
                if data is None:
                    raise ValueError("Data required for Davies-Bouldin score")
                results[method] = metrics.davies_bouldin_score(data, labels)
            elif method == 'adjusted_rand':
                if gold_standard is None:
                    raise ValueError("Gold standard required for adjusted Rand score")
                results[method] = metrics.adjusted_rand_score(gold_standard, labels)
            elif method == 'adjusted_mutual_info':
                if gold_standard is None:
                    raise ValueError("Gold standard required for adjusted mutual info score")
                results[method] = metrics.adjusted_mutual_info_score(gold_standard, labels)
            else:
                raise ValueError(f"Unknown metric: {method}")
        except Exception as e:
            results[method] = f"Error: {str(e)}"

    return results

