import json

def process_election_data(election_data):
    """
    Process election data and aggregate votes by state and candidate.

    Args:
        election_data (list): List of election data entries, where each entry contains:
            - Location (dict): Contains state information
            - Vote Data (dict): Contains candidate names and their vote counts

    Returns:
        dict: Nested dictionary with states as keys and candidate vote totals as values
    """
    election_output = {}

    for data in election_data:
        state_name = data["Location"]["State"]

        if state_name not in election_output:
            election_output[state_name] = {}

        for candidate_name, vote_data in data["Vote Data"].items():
            if candidate_name not in election_output[state_name]:
                election_output[state_name][candidate_name] = 0
            election_output[state_name][candidate_name] += vote_data["Number of Votes"]

    return election_output

def determine_state_winners(election_results):
    """
    Determine the winning candidate for each state based on vote counts.

    Args:
        election_results (dict): Processed election data from process_election_data()

    Returns:
        dict: Dictionary with states as keys and winning candidate names as values
    """
    state_winners = {}

    for state, candidates in election_results.items():
        max_votes = 0
        winner = None

        for candidate, votes in candidates.items():
            if votes > max_votes:
                max_votes = votes
                winner = candidate
            elif votes == max_votes:
                winner = f"Tie between {winner} and {candidate}"

        state_winners[state] = winner

    return state_winners

def determine_national_winner(election_results):
    """
    Determine the national winner by aggregating votes across all states.

    Args:
        election_results (dict): Processed election data from process_election_data()

    Returns:
        str: Name of the national winner or tie information
    """
    national_totals = {}

    for state in election_results.values():
        for candidate, votes in state.items():
            if candidate not in national_totals:
                national_totals[candidate] = 0
            national_totals[candidate] += votes

    max_votes = max(national_totals.values())
    winners = [c for c, v in national_totals.items() if v == max_votes]

    if len(winners) == 1:
        return winners[0]
    else:
        return f"National tie between: {', '.join(winners)}"

