def count_triangles(adjacency_matrix):
    """
    Counts the number of triangles in an undirected graph represented by an adjacency matrix.

    Args:
        adjacency_matrix: A square matrix (list of lists) where 1 represents an edge and 0 represents no edge.

    Returns:
        The number of triangles found in the graph.
    """
    n = len(adjacency_matrix)
    total_count = 0

    # Check all possible triplets of vertices (a, b, c)
    for a in range(n):
        for b in range(a + 1, n):
            if not adjacency_matrix[a][b]:
                continue  # Skip if no edge between a and b
            for c in range(b + 1, n):
                if adjacency_matrix[b][c] and adjacency_matrix[a][c]:
                    total_count += 1
    return total_count

import uuid
from datetime import datetime

class TimerService:
    def __init__(self):
        self.timers = {}
        self.stash = {}

    def start_timer(self, name=None):
        """Start a timer with optional name, returns timer ID"""
        timer_id = str(uuid.uuid1()) if name is None else name
        self.timers[timer_id] = datetime.now()
        return timer_id

    def end_timer(self, timer_id):
        """End a timer and return duration in seconds"""
        if timer_id not in self.timers:
            raise ValueError("Timer ID not found")

        start_time = self.timers[timer_id]
        duration = datetime.now() - start_time
        return duration.total_seconds()

    def get_all_timers(self):
        """Return all active timers"""
        return {k: v.isoformat() for k, v in self.timers.items()}

    def stash_item(self, item):
        """Store an item in stash and return its ID"""
        item_id = str(uuid.uuid1())
        self.stash[item_id] = item
        return item_id

    def unstash_item(self, item_id):
        """Retrieve an item from stash by ID"""
        if item_id not in self.stash:
            raise ValueError("Item ID not found")
        return self.stash[item_id]

    @staticmethod
    def split_string(splitter, item):
        """Split a string by the given splitter"""
        return item.split(splitter)

