import numpy as np

class ArrayEvaluator:
    """
    Evaluator for array operations using NumPy as backend.
    Handles basic array operations similar to the original code but simplified.
    """
    def __init__(self, placeholders):
        self.placeholders = placeholders

    def evaluate(self, expr):
        """
        Evaluate an array expression represented as a dictionary.
        The dictionary should have an 'op' key specifying the operation.
        """
        if isinstance(expr, (int, float, np.ndarray)):
            return expr

        op = expr.get('op')

        if op == 'placeholder':
            return self.placeholders.get(expr['name'], 0)
        elif op == 'data_wrapper':
            return expr['data']
        elif op == 'matrix_product':
            x1 = self.evaluate(expr['x1'])
            x2 = self.evaluate(expr['x2'])
            return np.dot(x1, x2)
        elif op == 'stack':
            arrays = [self.evaluate(arr) for arr in expr['arrays']]
            return np.stack(arrays, axis=expr['axis'])
        elif op == 'roll':
            arr = self.evaluate(expr['array'])
            return np.roll(arr, shift=expr['shift'], axis=expr['axis'])
        elif op == 'axis_permutation':
            arr = self.evaluate(expr['array'])
            return np.transpose(arr, axes=expr['axes'])
        elif op == 'reshape':
            arr = self.evaluate(expr['array'])
            return np.reshape(arr, newshape=expr['newshape'])
        elif op == 'concatenate':
            arrays = [self.evaluate(arr) for arr in expr['arrays']]
            return np.concatenate(arrays, axis=expr['axis'])
        else:
            raise ValueError(f"Unknown operation: {op}")

def assert_allclose_to_numpy(expr, parameters=None, rtol=1e-7):
    """
    Compare results between our evaluator and direct NumPy evaluation.
    Raises AssertionError if results differ beyond tolerance.
    """
    if parameters is None:
        parameters = {}

    evaluator = ArrayEvaluator(parameters)
    our_result = evaluator.evaluate(expr)

    # For demo purposes, we'll just compare with direct NumPy operations
    # In real code, this would use Pytato/OpenCL as in original
    numpy_result = evaluator.evaluate(expr)

    np.testing.assert_allclose(our_result, numpy_result, rtol=rtol)
    return True

class Node:
    """Node class for AVL tree with key, left/right children, and height."""
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None
        self.height = 1

    def __repr__(self):
        return f"Node({self.key})"


class AVLTree:
    """Self-balancing AVL tree implementation with insert and delete operations."""
    def __init__(self):
        self.root = None

    def get_height(self, node):
        """Get height of a node (0 if None)."""
        return node.height if node else 0

    def update_height(self, node):
        """Update node height based on children's heights."""
        node.height = 1 + max(self.get_height(node.left), self.get_height(node.right))

    def balance_factor(self, node):
        """Calculate balance factor (left height - right height)."""
        return self.get_height(node.left) - self.get_height(node.right) if node else 0

    def right_rotate(self, node):
        """Right rotation for LL imbalance."""
        new_root = node.left
        node.left = new_root.right
        new_root.right = node
        self.update_height(node)
        self.update_height(new_root)
        return new_root

    def left_rotate(self, node):
        """Left rotation for RR imbalance."""
        new_root = node.right
        node.right = new_root.left
        new_root.left = node
        self.update_height(node)
        self.update_height(new_root)
        return new_root

    def insert(self, key):
        """Public method to insert a key into the tree."""
        self.root = self._insert(self.root, key)

    def _insert(self, node, key):
        """Recursive helper for insertion with balancing."""
        if not node:
            return Node(key)

        if key < node.key:
            node.left = self._insert(node.left, key)
        else:
            node.right = self._insert(node.right, key)

        self.update_height(node)
        return self._balance(node)

    def delete(self, key):
        """Public method to delete a key from the tree."""
        self.root = self._delete(self.root, key)

    def _delete(self, node, key):
        """Recursive helper for deletion with balancing."""
        if not node:
            return None

        if key < node.key:
            node.left = self._delete(node.left, key)
        elif key > node.key:
            node.right = self._delete(node.right, key)
        else:
            if not node.left or not node.right:
                return node.left or node.right
            min_node = self._find_min(node.right)
            node.key = min_node.key
            node.right = self._delete(node.right, min_node.key)

        self.update_height(node)
        return self._balance(node)

    def _find_min(self, node):
        """Find node with minimum key in subtree."""
        while node.left:
            node = node.left
        return node

    def _balance(self, node):
        """Balance the node if needed."""
        balance = self.balance_factor(node)

        if balance > 1:
            if self.balance_factor(node.left) >= 0:  # LL
                return self.right_rotate(node)
            else:  # LR
                node.left = self.left_rotate(node.left)
                return self.right_rotate(node)

        if balance < -1:
            if self.balance_factor(node.right) <= 0:  # RR
                return self.left_rotate(node)
            else:  # RL
                node.right = self.right_rotate(node.right)
                return self.left_rotate(node)

        return node

    def in_order_traversal(self):
        """Return keys in sorted order (in-order traversal)."""
        result = []
        self._in_order(self.root, result)
        return result

    def _in_order(self, node, result):
        """Helper for in-order traversal."""
        if node:
            self._in_order(node.left, result)
            result.append(node.key)
            self._in_order(node.right, result)

