class LecturerManager:
    """A class to manage lecturer records in memory without file I/O"""

    def __init__(self):
        self.lecturer_fields = ['ID', 'First Name', 'Last Name', 'Email', 'Phone', 'Course']
        self.lecturers = []

    def add_lecturer(self, lecturer_data):
        """Add a new lecturer record"""
        if len(lecturer_data) != len(self.lecturer_fields):
            return False, "Invalid data length"

        # Check for duplicate ID
        for lecturer in self.lecturers:
            if lecturer[0] == lecturer_data[0]:
                return False, "Duplicate ID"

        self.lecturers.append(lecturer_data)
        return True, "Lecturer added successfully"

    def view_lecturers(self):
        """Return all lecturer records"""
        return self.lecturers

    def search_lecturer(self, lecturer_id):
        """Search for a lecturer by ID"""
        for lecturer in self.lecturers:
            if lecturer[0] == lecturer_id:
                return True, lecturer
        return False, "Lecturer not found"

    def update_lecturer(self, lecturer_id, new_data):
        """Update a lecturer record"""
        if len(new_data) != len(self.lecturer_fields):
            return False, "Invalid data length"

        for i, lecturer in enumerate(self.lecturers):
            if lecturer[0] == lecturer_id:
                # Don't allow ID change
                if new_data[0] != lecturer_id:
                    return False, "Cannot change lecturer ID"
                self.lecturers[i] = new_data
                return True, "Lecturer updated successfully"
        return False, "Lecturer not found"

    def delete_lecturer(self, lecturer_id):
        """Delete a lecturer record"""
        for i, lecturer in enumerate(self.lecturers):
            if lecturer[0] == lecturer_id:
                del self.lecturers[i]
                return True, "Lecturer deleted successfully"
        return False, "Lecturer not found"

