def authenticate_user(username, password):
    """
    Simulates user authentication with basic validation rules.
    Returns a dictionary with authentication status and details.

    Rules:
    - Valid credentials: username='brian123', password='123456'
    - Username and password must be strings
    - Both fields must be present
    - Whitespace around credentials is trimmed
    """

    # Input validation
    if not isinstance(username, str) or not isinstance(password, str):
        return {
            'status': 'error',
            'status_code': 400,
            'description': 'Not a valid string.'
        }

    if not username or not password:
        missing_fields = []
        if not username:
            missing_fields.append('username')
        if not password:
            missing_fields.append('password')
        return {
            'status': 'error',
            'status_code': 400,
            'description': f'Missing data for required field(s): {", ".join(missing_fields)}.'
        }

    # Trim whitespace
    username = username.strip()
    password = password.strip()

    # Authentication check
    if username == 'brian123' and password == '123456':
        return {
            'status': 'success',
            'status_code': 200,
            'access_token': 'simulated_token',
            'user': {
                'username': username,
                'id': 1
            }
        }
    else:
        return {
            'status': 'error',
            'status_code': 401,
            'description': 'Invalid Credentials.'
        }

