def compute_attribute_closure(attributes, functional_deps):
    """
    Compute the closure of a set of attributes given functional dependencies.

    Args:
        attributes (str): The set of attributes to compute closure for (e.g., 'A', 'CD')
        functional_deps (dict): Functional dependencies in format {'AB': ['C'], 'C': ['AD']}

    Returns:
        str: The closure of the input attributes (e.g., 'ABCD')
    """
    closure = set(attributes)
    changed = True

    while changed:
        changed = False
        # Check each functional dependency
        for lhs, rhs_list in functional_deps.items():
            for rhs in rhs_list:
                # If all attributes in LHS are in our current closure
                if all(attr in closure for attr in lhs):
                    # Add RHS attributes to closure if not already present
                    for attr in rhs:
                        if attr not in closure:
                            closure.add(attr)
                            changed = True
    return ''.join(sorted(closure))

from collections import defaultdict

class PinyinCounter:
    """Counts occurrences of pinyin pronunciations for Chinese characters."""

    def __init__(self):
        self.counts = defaultdict(int)

    def add(self, pinyin):
        """Increment count for a pinyin pronunciation."""
        self.counts[pinyin] += 1

    def most_common(self, n=None):
        """Return most common pinyin(s) sorted by frequency.

        Args:
            n: Number of top results to return (None for all)
        Returns:
            List of (pinyin, count) tuples sorted by count descending
        """
        sorted_items = sorted(self.counts.items(), key=lambda x: x[1], reverse=True)
        return sorted_items[:n] if n else sorted_items

def han_to_code(han_char):
    """Convert a Chinese character to its Unicode code point.

    Args:
        han_char: Single Chinese character string
    Returns:
        String in format 'U+XXXX' representing Unicode code point
    """
    return f"U+{ord(han_char):04X}"

def process_characters(character_data):
    """Process Chinese characters and their pinyin pronunciations.

    Args:
        character_data: Dictionary of {character: [pinyin_list]}
    Returns:
        Dictionary of {character: PinyinCounter} with pronunciation counts
    """
    han_counter = {}

    for character, pinyin_list in character_data.items():
        if len(character) != len(pinyin_list):
            continue

        for han_char, pinyins in zip(character, pinyin_list):
            if han_char not in han_counter:
                han_counter[han_char] = PinyinCounter()

            for pinyin in pinyins:
                han_counter[han_char].add(pinyin)

    return han_counter

