def validate_age(age):
    """
    Validates if an age is within reasonable human lifespan range (0-120).
    Also checks for valid numeric input and handles edge cases.

    Args:
        age: The age to validate (can be int, float, or string representation)

    Returns:
        dict: Contains validation result and additional information
        {
            'valid': bool,
            'message': str,
            'normalized_age': float or None
        }
    """
    try:
        # Convert input to float (handles strings and numeric types)
        age_float = float(age)

        # Check for negative age
        if age_float < 0:
            return {
                'valid': False,
                'message': 'Age cannot be negative',
                'normalized_age': None
            }

        # Check for unreasonably high age
        if age_float > 120:
            return {
                'valid': False,
                'message': 'Age exceeds maximum human lifespan',
                'normalized_age': None
            }

        # Check for fractional ages (like 2.5 years)
        if not age_float.is_integer():
            return {
                'valid': True,
                'message': 'Age is valid but contains decimal places',
                'normalized_age': age_float
            }

        # Valid integer age
        return {
            'valid': True,
            'message': 'Valid age',
            'normalized_age': int(age_float)
        }

    except (ValueError, TypeError):
        return {
            'valid': False,
            'message': 'Invalid age format - must be numeric',
            'normalized_age': None
        }

