        """Get height of a node (0 if None)."""
        return node.height if node else 0

    def update_height(self, node):
        """Update node height based on children's heights."""
        node.height = 1 + max(self.get_height(node.left), self.get_height(node.right))

    def balance_factor(self, node):
        """Calculate balance factor (left height - right height)."""
        return self.get_height(node.left) - self.get_height(node.right) if node else 0

    def right_rotate(self, node):
        """Right rotation for LL imbalance."""
        new_root = node.left
        node.left = new_root.right
        new_root.right = node
        self.update_height(node)
        self.update_height(new_root)
        return new_root

    def left_rotate(self, node):
        """Left rotation for RR imbalance."""
        new_root = node.right
        node.right = new_root.left
        new_root.left = node
        self.update_height(node)
        self.update_height(new_root)
        return new_root

    def insert(self, key):
        """Public method to insert a key into the tree."""
        self.root = self._insert(self.root, key)

    def _insert(self, node, key):
        """Recursive helper for insertion with balancing."""
        if not node:
            return Node(key)

        if key < node.key:
            node.left = self._insert(node.left, key)
        else:
            node.right = self._insert(node.right, key)

        self.update_height(node)
        return self._balance(node)

    def delete(self, key):
        """Public method to delete a key from the tree."""
        self.root = self._delete(self.root, key)

    def _delete(self, node, key):
        """Recursive helper for deletion with balancing."""
        if not node:
            return None

        if key < node.key:
            node.left = self._delete(node.left, key)
        elif key > node.key:
            node.right = self._delete(node.right, key)
        else:
            if not node.left or not node.right:
                return node.left or node.right
            min_node = self._find_min(node.right)
            node.key = min_node.key
            node.right = self._delete(node.right, min_node.key)

        self.update_height(node)
        return self._balance(node)

    def _find_min(self, node):
        """Find node with minimum key in subtree."""
        while node.left:
            node = node.left
        return node

    def _balance(self, node):
        """Balance the node if needed."""
        balance = self.balance_factor(node)

        if balance > 1:
            if self.balance_factor(node.left) >= 0:  # LL
                return self.right_rotate(node)
            else:  # LR
                node.left = self.left_rotate(node.left)
                return self.right_rotate(node)

        if balance < -1:
            if self.balance_factor(node.right) <= 0:  # RR
                return self.left_rotate(node)
            else:  # RL
                node.right = self.right_rotate(node.right)
                return self.left_rotate(node)

        return node

    def in_order_traversal(self):
        """Return keys in sorted order (in-order traversal)."""
        result = []
        self._in_order(self.root, result)
        return result

    def _in_order(self, node, result):
        """Helper for in-order traversal."""
        if node:
            self._in_order(node.left, result)
            result.append(node.key)
            self._in_order(node.right, result)

