import re

def validate_exception_raising(raised_exception, expected_exception, message=None, match_pattern=None, match_flags=0):
    """
    Validate that a raised exception matches expected criteria.

    Args:
        raised_exception: The exception that was raised (or None if no exception).
        expected_exception: The expected exception class.
        message: Expected substring in exception message (optional).
        match_pattern: Regex pattern to match against message (optional).
        match_flags: Flags for regex matching (default 0).

    Returns:
        tuple: (is_valid, error_message) where is_valid is bool and error_message is str or None.
    """
    # Validate expected_exception is a proper exception class
    if not isinstance(expected_exception, type) or not issubclass(expected_exception, BaseException):
        return (False, f"Supplied `exception={expected_exception}` is not a valid exception class.")

    # Only one of message or match_pattern should be provided
    if message and match_pattern:
        return (False, "Only `message` OR `match` allowed, not both.")

    # Case 1: No exception was raised but one was expected
    if raised_exception is None:
        return (False, f"Expected exception {expected_exception}, but it did not raise")

    # Case 2: Wrong exception type was raised
    if not isinstance(raised_exception, expected_exception):
        return (False, 
                f"Expected exception of type {expected_exception}, but got {type(raised_exception)} "
                f"with message: {str(raised_exception)}")

    # Case 3: Correct exception type, check message if provided
    raised_message = str(raised_exception)
    if message is not None:
        if message not in raised_message:
            return (False, f'"{message}" not in "{raised_message}"')
    elif match_pattern is not None:
        if not re.match(match_pattern, raised_message, match_flags):
            return (False, f'"{match_pattern}" does not match raised message "{raised_message}"')

    # All checks passed
    return (True, None)

