def get_sequence(sequence=None, filepath=None):
    """
    Retrieve a sequence either from a direct string input or from a file.

    Args:
        sequence (str, optional): Direct sequence string input. Defaults to None.
        filepath (str, optional): Path to file containing sequence. Defaults to None.

    Returns:
        str: The retrieved sequence, or None if neither input is valid or file not found.
