class AttributeManager:
    """Manages attributes in a hierarchical structure (entity_type -> name -> attribute)."""
    def __init__(self):
        self.entity_map = {}
        self.transient = False

    def is_transient(self):
        """Returns whether the manager is in transient state."""
        return self.transient

    def set_transient(self, transient):
        """Sets the transient state of the manager."""
        self.transient = transient

    def set_attribute(self, entity_type, name, attribute, value, unit):
        """
        Sets an attribute with value and unit in the hierarchical structure.

        Args:
            entity_type: The type of entity (top-level category)
            name: The name of the specific entity
            attribute: The attribute name to set
            value: The value to store
            unit: The unit of measurement
        """
        if entity_type not in self.entity_map:
            self.entity_map[entity_type] = {}
        if name not in self.entity_map[entity_type]:
            self.entity_map[entity_type][name] = {}
        self.entity_map[entity_type][name][attribute] = Value(value, unit)

    def get_attribute(self, entity_type, name, attribute):
        """
        Retrieves an attribute value with its unit.

        Returns:
            Value object or None if not found
        """
        try:
            return self.entity_map[entity_type][name][attribute]
        except KeyError:
            return None

