def find_numbers_with_remainders(val1, val2):
    """
    Find all numbers between two given values (exclusive) that have a remainder 
    of 2 or 3 when divided by 5.

    Args:
        val1 (int): First boundary value
        val2 (int): Second boundary value

    Returns:
        list: A sorted list of numbers meeting the criteria
    """
    result = []

    if val1 < val2:
        val1 += 1
        while val1 < val2:
            if val1 % 5 == 2 or val1 % 5 == 3:
                result.append(val1)
            val1 += 1
    elif val2 < val1:
        val2 += 1
        while val2 < val1:
            if val2 % 5 == 2 or val2 % 5 == 3:
                result.append(val2)
            val2 += 1

    return sorted(result)

class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size
        self.count = 0  # Number of islands

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # Path compression
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return

        # Union by rank
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        self.count -= 1

def num_islands_2(m, n, positions):
    if m <= 0 or n <= 0:
        return []

    uf = UnionFind(m * n)
    grid = [[0 for _ in range(n)] for _ in range(m)]
    result = []

    for i, j in positions:
        if grid[i][j] == 1:  # Already land
            result.append(uf.count)
            continue

        grid[i][j] = 1
        uf.count += 1
        index = i * n + j

        # Check four neighbors
        for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and grid[ni][nj] == 1:
                neighbor_index = ni * n + nj
                uf.union(index, neighbor_index)

        result.append(uf.count)

    return result

class Node:
    """Node for circular singly linked list"""
    def __init__(self, elem):
        self.elem = elem
        self.next = None


class CircularSinglyLinkedList:
    """Circular singly linked list implementation"""
    def __init__(self):
        self.head = None

    def is_empty(self):
        """Check if list is empty"""
        return self.head is None

    def length(self):
        """Return length of list"""
        if self.is_empty():
            return 0
        current = self.head
        count = 1
        while current.next != self.head:
            count += 1
            current = current.next
        return count

    def append(self, elem):
        """Append element to end of list"""
        new_node = Node(elem)
        if self.is_empty():
            self.head = new_node
            new_node.next = self.head
        else:
            current = self.head
            while current.next != self.head:
                current = current.next
            current.next = new_node
            new_node.next = self.head

    def prepend(self, elem):
        """Prepend element to start of list"""
        new_node = Node(elem)
        if self.is_empty():
            self.head = new_node
            new_node.next = self.head
        else:
            current = self.head
            while current.next != self.head:
                current = current.next
            current.next = new_node
            new_node.next = self.head
            self.head = new_node

    def remove(self, elem):
        """Remove first occurrence of element from list"""
        if self.is_empty():
            return False

        current = self.head
        prev = None

        # Case 1: Head node is to be removed
        if current.elem == elem:
            if current.next == self.head:  # Only one node
                self.head = None
            else:
                # Find the last node
                last = self.head
                while last.next != self.head:
                    last = last.next
                self.head = current.next
                last.next = self.head
            return True

        # Case 2: Non-head node to be removed
        while current.next != self.head:
            if current.elem == elem:
                prev.next = current.next
                return True
            prev = current
            current = current.next

        # Check last node
        if current.elem == elem:
            prev.next = current.next
            return True

        return False

    def to_list(self):
        """Convert linked list to Python list"""
        if self.is_empty():
            return []
        result = []
        current = self.head
        while True:
            result.append(current.elem)
            current = current.next
            if current == self.head:
                break
        return result

