import re

def process_import_data(fields, mandatory, import_data, query_mapping):
    """
    Simulates importing data into a database by processing queries with marker replacements.

    Args:
        fields: List of field names corresponding to the data columns
        mandatory: List of mandatory field names
        import_data: List of records (each record is a list/tuple of values)
        query_mapping: Dictionary containing PRE, IMPORT, and POST query templates

    Returns:
        Dictionary containing the final state of all processed data markers
    """
    data = {}
    updated = False

    def replace_markers(query_template, marker_data):
        """Replace markers (#marker#) in query templates with actual values"""
        query = query_template
        markers = re.findall('#([^#]+)#', query)
        for marker in markers:
            value = ''
            if marker in marker_data:
                value = str(marker_data[marker]).replace("'", "\\'")
            query = query.replace(f'#{marker}#', value)
        return query

    def check_exists(search_template, marker_data):
        """Simulate checking if a record exists (always returns None in this simulation)"""
        search_query = replace_markers(search_template, marker_data)
        return None  # Simulating no existing record found

    # Process PRE queries
    try:
        for query in query_mapping['PRE']:
            if 'SEARCH' in query:
                search_query = query['SEARCH']
                if 'uid_marker' in search_query:
                    data[search_query['uid_marker']] = check_exists(
                        search_query['query'], data)
    except KeyError:
        pass  # No PRE queries

    data_backup = data.copy()

    # Process IMPORT data
    for record in import_data:
        record_data = dict(zip(fields, record))
        all_mandatory = all(record_data.get(field, None) for field in mandatory)

        if not all_mandatory:
            continue  # Skip records missing mandatory fields

        current_data = {**data_backup, **record_data}

        for query in query_mapping['IMPORT']:
            if 'SEARCH' in query:
                search_query = query['SEARCH']
                if 'uid_marker' in search_query:
                    current_data[search_query['uid_marker']] = check_exists(
                        search_query['query'], current_data)

            elif 'UPDATE' in query:
                update_query = query['UPDATE']
                if ('uid_marker' in update_query and 
                    update_query['uid_marker'] in current_data and 
                    current_data[update_query['uid_marker']] is not None):
                    replace_markers(update_query['query'], current_data)
                    updated = True

            elif 'INSERT' in query:
                insert_query = query['INSERT']
                if not updated or not insert_query.get('fallback', False):
                    replace_markers(insert_query['query'], current_data)
                    if 'uid_marker' in insert_query:
                        current_data[insert_query['uid_marker']] = 123  # Simulated new ID
                else:
                    updated = False

    # Process POST queries
    try:
        for query in query_mapping['POST']:
            if 'SEARCH' in query:
                search_query = query['SEARCH']
                if 'uid_marker' in search_query:
                    data[search_query['uid_marker']] = check_exists(
                        search_query['query'], data)
    except KeyError:
        pass  # No POST queries

    return data

