class BookManager:
    def __init__(self, books):
        self.books = books
        self.current_index = 0

    def get_next_book(self):
        if len(self.books) == 0:
            return None
        self.current_index = (self.current_index + 1) % len(self.books)
        return self.books[self.current_index]

    def get_prev_book(self):
        if len(self.books) == 0:
            return None
        self.current_index = (self.current_index - 1) % len(self.books)
        return self.books[self.current_index]

    def get_cheapest_books(self, count=5):
        if len(self.books) == 0:
            return []
        return sorted(self.books, key=lambda x: x.price)[:count]

    def get_highest_rated_books(self, count=5):
        if len(self.books) == 0:
            return []
        return sorted(self.books, key=lambda x: -x.rating)[:count]

import math
import copy
from typing import List, Dict, Union

class DecisionTree:
    """A simplified decision tree classifier that handles both numeric and categorical features."""

    def __init__(self, end_point: float = 0.8):
        self.end_point = end_point
        self.tree = None

    def calculate_entropy(self, labels: List[str]) -> float:
        """Calculate entropy of a set of labels."""
        n = len(labels)
        if n == 0:
            return 0.0

        record = {}
        for label in labels:
            record[label] = record.get(label, 0) + 1

        entropy = 0.0
        for count in record.values():
            pxi = float(count) / n
            entropy -= pxi * math.log(pxi, 2)
        return entropy

    def split_data_numeric(self, data: List[dict], feature: str) -> Dict[str, List[dict]]:
        """Split data based on numeric feature."""
        avg = sum(d[feature] for d in data) / len(data)
        subsets = {
            f"< {avg}": [d for d in data if d[feature] < avg],
            f">= {avg}": [d for d in data if d[feature] >= avg]
        }
        return subsets

    def split_data_categorical(self, data: List[dict], feature: str) -> Dict[str, List[dict]]:
        """Split data based on categorical feature."""
        subsets = {}
        for d in data:
            key = d[feature]
            if key not in subsets:
                subsets[key] = []
            subsets[key].append(d)
        return subsets

    def find_majority_label(self, labels: List[str]) -> str:
        """Find the majority label in a set."""
        counts = {}
        for label in labels:
            counts[label] = counts.get(label, 0) + 1
        return max(counts.items(), key=lambda x: x[1])[0]

    def find_best_feature(self, data: List[dict], features: List[str], numeric_features: List[str]) -> tuple:
        """Find the feature that provides the best split."""
        best_feature = None
        min_entropy = float('inf')
        best_subsets = None
        is_numeric = False

        labels = [d['label'] for d in data]
        base_entropy = self.calculate_entropy(labels)

        for feature in features:
            if feature in numeric_features:
                subsets = self.split_data_numeric(data, feature)
                is_numeric_current = True
            else:
                subsets = self.split_data_categorical(data, feature)
                is_numeric_current = False

            new_entropy = 0.0
            for subset in subsets.values():
                subset_labels = [d['label'] for d in subset]
                prob = len(subset) / len(data)
                new_entropy += prob * self.calculate_entropy(subset_labels)

            info_gain = base_entropy - new_entropy
            if info_gain > 0 and new_entropy < min_entropy:
                min_entropy = new_entropy
                best_feature = feature
                best_subsets = subsets
                is_numeric = is_numeric_current

        return best_feature, best_subsets, is_numeric

    def build_tree(self, data: List[dict], features: List[str], numeric_features: List[str]) -> Union[dict, str]:
        """Recursively build the decision tree."""
        labels = [d['label'] for d in data]

        # Stopping conditions
        if not data:
            return "NULL"
        if all(label == labels[0] for label in labels):
            return labels[0]
        if len(features) == 0:
            return self.find_majority_label(labels)

        # Check if majority class exceeds end_point
        majority_label = self.find_majority_label(labels)
        if labels.count(majority_label) / len(labels) > self.end_point:
            return majority_label

        # Find best feature to split on
        best_feature, subsets, is_numeric = self.find_best_feature(
            data, features, numeric_features
        )

        if not best_feature:
            return self.find_majority_label(labels)

        # Create node
        node = {best_feature: {}}
        remaining_features = [f for f in features if f != best_feature]

        for value, subset in subsets.items():
            node[best_feature][value] = self.build_tree(
                subset, remaining_features, numeric_features
            )

        return node

    def fit(self, data: List[dict], numeric_features: List[str]):
        """Train the decision tree."""
        features = [key for key in data[0].keys() if key != 'label']
        self.tree = self.build_tree(data, features, numeric_features)

    def predict(self, sample: dict) -> str:
        """Predict the label for a single sample."""
        if not self.tree:
            raise ValueError("Model not trained yet. Call fit() first.")

        return self._predict_sample(sample, self.tree)

    def _predict_sample(self, sample: dict, node: Union[dict, str]) -> str:
        """Recursively traverse the tree to make a prediction."""
        if isinstance(node, str):
            return node

        feature = list(node.keys())[0]
        value = sample[feature]
        subtree = node[feature]

        if isinstance(value, (int, float)):
            # Numeric feature
            for key in subtree:
                if key.startswith('<'):
                    threshold = float(key[2:])
                    if value < threshold:
                        return self._predict_sample(sample, subtree[key])
                elif key.startswith('>='):
                    threshold = float(key[2:])
                    if value >= threshold:
                        return self._predict_sample(sample, subtree[key])
        else:
            # Categorical feature
            if value in subtree:
                return self._predict_sample(sample, subtree[value])

        # If value not found, return most common class
        return "unknown"
